#include <stdio.h>
int main() {
    int x = 5;
    int *p = &x;
    *p = 10;
    printf("%d", x);
    return 0;
}

#include <stdio.h>
int main() {
    int a = 1, b = 2;
    int *p = &a, *q = &b;
    p = q;
    *p = 9;
    printf("%d %d", a, b);
    return 0;
}

#include <stdio.h>
int main() {
    int arr[] = {10, 20, 30};
    int *p = arr;
    printf("%d", *(p + 1) + 1);
    return 0;
}

#include <stdio.h>
void f(int *p) { p = NULL; }
